        assertEquals(1, entries.size(), "Expected exactly one entry");
        io.github.cdimascio.dotenv.DotenvEntry e = entries.iterator().next(); // Updated import
        assertEquals("ONE", e.getKey());
        assertEquals("1", e.getValue());
    }

